/**
 * Middleware Tests (node environment)
 *
 * Testa o middleware Next.js:
 *   - Rotas públicas passam sem auth
 *   - Rotas protegidas redirecionam sem auth
 *   - Redirect para studio-pro se autenticado em rota de auth
 *   - Rate limiting em API routes
 *   - Security headers
 *   - Bypass de recursos estáticos/_next
 *   - Legacy studio redirects
 *   - Error handling quando Supabase falha
 */

// ─── Mocks ───────────────────────────────────────────────────────────────────

const mockGetUser = jest.fn();

jest.mock('@lib/supabase/middleware', () => ({
  createClient: jest.fn((_req: unknown) => {
    const { NextResponse } = require('next/server');
    return {
      supabase: {
        auth: {
          getUser: mockGetUser,
        },
      },
      response: NextResponse.next(),
    };
  }),
}));

// ─── Imports ─────────────────────────────────────────────────────────────────

import { NextRequest } from 'next/server';
import { middleware } from '../../middleware';

// ─── Helpers ─────────────────────────────────────────────────────────────────

function createRequest(
  pathname: string,
  options: {
    method?: string;
    headers?: Record<string, string>;
    protocol?: string;
    hostname?: string;
  } = {}
): NextRequest {
  const url = `http://${options.hostname ?? 'localhost'}:3000${pathname}`;
  const req = new NextRequest(url, {
    method: options.method ?? 'GET',
    headers: options.headers,
  });
  return req;
}

// ─── Tests ───────────────────────────────────────────────────────────────────

describe('Middleware', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockGetUser.mockResolvedValue({ data: { user: null } });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // Static Assets & _next bypass
  // ════════════════════════════════════════════════════════════════════════════

  describe('Static Assets Bypass', () => {
    it('should pass through _next/ resources', async () => {
      const req = createRequest('/_next/static/chunks/main.js');
      const res = await middleware(req);

      expect(res.status).toBe(200);
    });

    it('should pass through favicon', async () => {
      const req = createRequest('/favicon.ico');
      const res = await middleware(req);

      expect(res.status).toBe(200);
    });

    it('should pass through /api/auth/ routes', async () => {
      const req = createRequest('/api/auth/callback');
      const res = await middleware(req);

      expect(res.status).toBe(200);
    });

    it('should pass through static file extensions', async () => {
      const extensions = ['.css', '.js', '.png', '.jpg', '.svg', '.woff2', '.json'];
      for (const ext of extensions) {
        const req = createRequest(`/assets/file${ext}`);
        const res = await middleware(req);
        expect(res.status).toBe(200);
      }
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // Public Routes
  // ════════════════════════════════════════════════════════════════════════════

  describe('Public Routes', () => {
    const publicPaths = [
      '/',
      '/login',
      '/register',
      '/pricing',
      '/blog',
      '/terms',
      '/privacy',
      '/ajuda',
      '/help',
      '/auth',
    ];

    it.each(publicPaths)(
      'should allow %s without auth check',
      async (path) => {
        const req = createRequest(path);
        const res = await middleware(req);

        expect(res.status).toBe(200);
      }
    );

    it('should apply security headers to public routes', async () => {
      const req = createRequest('/');
      const res = await middleware(req);

      expect(res.headers.get('X-Content-Type-Options')).toBe('nosniff');
      expect(res.headers.get('X-Frame-Options')).toBe('DENY');
      expect(res.headers.get('X-XSS-Protection')).toBe('1; mode=block');
      expect(res.headers.get('Referrer-Policy')).toBe(
        'strict-origin-when-cross-origin'
      );
    });

    it('should allow blog sub-routes', async () => {
      const req = createRequest('/blog/meu-artigo');
      const res = await middleware(req);

      expect(res.status).toBe(200);
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // Protected Routes — No Auth
  // ════════════════════════════════════════════════════════════════════════════

  describe('Protected Routes (unauthenticated)', () => {
    beforeEach(() => {
      mockGetUser.mockResolvedValue({ data: { user: null } });
    });

    it.each([
      '/studio',
      '/studio-pro',
      '/editor',
      '/projects',
      '/create',
      '/ppt-to-video',
    ])(
      'should redirect %s to /login when unauthenticated',
      async (path) => {
        const req = createRequest(path);
        const res = await middleware(req);

        expect(res.status).toBe(307);
        const location = res.headers.get('location');
        expect(location).toContain('/login');
        expect(location).toContain(`redirect=${encodeURIComponent(path)}`);
      }
    );
  });

  // ════════════════════════════════════════════════════════════════════════════
  // Protected Routes — Authenticated
  // ════════════════════════════════════════════════════════════════════════════

  describe('Protected Routes (authenticated)', () => {
    beforeEach(() => {
      mockGetUser.mockResolvedValue({
        data: { user: { id: 'user-123', email: 'user@test.com' } },
      });
    });

    it('should allow access to /studio-pro', async () => {
      const req = createRequest('/studio-pro');
      const res = await middleware(req);

      // Should NOT redirect (200 from NextResponse.next())
      expect(res.status).toBe(200);
    });

    it('should redirect /login to /studio-pro when already authenticated', async () => {
      const req = createRequest('/login');
      const res = await middleware(req);

      expect(res.status).toBe(307);
      expect(res.headers.get('location')).toContain('/studio-pro');
    });

    it('should redirect /register to /studio-pro when already authenticated', async () => {
      const req = createRequest('/register');
      const res = await middleware(req);

      expect(res.status).toBe(307);
      expect(res.headers.get('location')).toContain('/studio-pro');
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // Legacy Studio Redirects
  // ════════════════════════════════════════════════════════════════════════════

  describe('Legacy Studio Redirects', () => {
    it('should redirect /dashboard to /studio-pro when authenticated', async () => {
      mockGetUser.mockResolvedValue({
        data: { user: { id: 'user-123' } },
      });

      const req = createRequest('/dashboard');
      const res = await middleware(req);

      expect(res.status).toBe(307);
      expect(res.headers.get('location')).toContain('/studio-pro');
    });

    it('should redirect /dashboard to /login when unauthenticated', async () => {
      mockGetUser.mockResolvedValue({ data: { user: null } });

      const req = createRequest('/dashboard');
      const res = await middleware(req);

      expect(res.status).toBe(307);
      const location = res.headers.get('location') ?? '';
      expect(location).toContain('/login');
      expect(location).toContain('redirect=%2Fstudio-pro');
    });

    it('should redirect /dashboard/projects to /studio-pro', async () => {
      mockGetUser.mockResolvedValue({
        data: { user: { id: 'user-123' } },
      });

      const req = createRequest('/dashboard/projects');
      const res = await middleware(req);

      expect(res.status).toBe(307);
      expect(res.headers.get('location')).toContain('/studio-pro');
    });

    it('should redirect /render-dashboard to /studio-pro', async () => {
      mockGetUser.mockResolvedValue({
        data: { user: { id: 'user-123' } },
      });

      const req = createRequest('/render-dashboard');
      const res = await middleware(req);

      expect(res.status).toBe(307);
      expect(res.headers.get('location')).toContain('/studio-pro');
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // API Rate Limiting
  // ════════════════════════════════════════════════════════════════════════════

  describe('API Rate Limiting', () => {
    it('should allow API requests within limit', async () => {
      mockGetUser.mockResolvedValue({ data: { user: null } });
      const req = createRequest('/api/health', {
        headers: { 'x-forwarded-for': '10.0.0.99' },
      });
      const res = await middleware(req);

      expect(res.status).not.toBe(429);
    });

    it('should return 429 after exceeding 500 requests', async () => {
      // Create unique IP per test to isolate from other tests
      const testIp = `10.99.${Math.floor(Math.random() * 255)}.${Math.floor(Math.random() * 255)}`;

      // Simulate 501 requests from same IP
      let lastRes;
      for (let i = 0; i < 501; i++) {
        const req = createRequest('/api/health', {
          headers: { 'x-forwarded-for': testIp },
        });
        lastRes = await middleware(req);
      }

      expect(lastRes!.status).toBe(429);
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // API Security Headers
  // ════════════════════════════════════════════════════════════════════════════

  describe('API Security Headers', () => {
    beforeEach(() => {
      mockGetUser.mockResolvedValue({ data: { user: null } });
    });

    it('should apply all security headers to API responses', async () => {
      const req = createRequest('/api/projects');
      const res = await middleware(req);

      expect(res.headers.get('X-Content-Type-Options')).toBe('nosniff');
      expect(res.headers.get('X-Frame-Options')).toBe('DENY');
      expect(res.headers.get('X-XSS-Protection')).toBe('1; mode=block');
      expect(res.headers.get('Referrer-Policy')).toBe(
        'strict-origin-when-cross-origin'
      );
      expect(res.headers.get('Strict-Transport-Security')).toContain(
        'max-age=63072000'
      );
    });

    it('should set cache-control: public for cacheable GET endpoints', async () => {
      const req = createRequest('/api/nr/courses');
      const res = await middleware(req);

      expect(res.headers.get('Cache-Control')).toContain('public');
      expect(res.headers.get('Cache-Control')).toContain('s-maxage=60');
    });

    it('should set cache-control: private for non-cacheable GET', async () => {
      const req = createRequest('/api/projects');
      const res = await middleware(req);

      expect(res.headers.get('Cache-Control')).toContain('private');
    });

    it('should set cache-control: no-store for POST', async () => {
      const req = createRequest('/api/projects', { method: 'POST' });
      const res = await middleware(req);

      expect(res.headers.get('Cache-Control')).toBe('no-store');
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // Error Handling
  // ════════════════════════════════════════════════════════════════════════════

  describe('Error Handling (Supabase failure)', () => {
    beforeEach(() => {
      mockGetUser.mockRejectedValue(new Error('Supabase unreachable'));
      // Suppress console.error output in tests
      jest.spyOn(console, 'error').mockImplementation(() => undefined);
    });

    afterEach(() => {
      jest.restoreAllMocks();
    });

    it('should return 503 for API routes when Supabase fails', async () => {
      const req = createRequest('/api/projects');
      const res = await middleware(req);

      expect(res.status).toBe(503);
      const body = await res.json();
      expect(body.code).toBe('MIDDLEWARE_ERROR');
    });

    it('should redirect protected routes to /login with error param', async () => {
      const req = createRequest('/studio-pro');
      const res = await middleware(req);

      expect(res.status).toBe(307);
      const location = res.headers.get('location') ?? '';
      expect(location).toContain('/login');
      expect(location).toContain('error=service_unavailable');
    });

    it('should still allow public routes with security headers', async () => {
      // Public routes skip Supabase entirely, so this scenario
      // only applies when the route isn't recognized as public
      const req = createRequest('/some-unknown-page');
      const res = await middleware(req);

      // Unknown page goes through Supabase path → error → treated as public fallback
      expect(res.headers.get('X-Content-Type-Options')).toBe('nosniff');
    });
  });

  // ════════════════════════════════════════════════════════════════════════════
  // Path normalization
  // ════════════════════════════════════════════════════════════════════════════

  describe('Path Normalization', () => {
    it('should treat /blog/ same as /blog', async () => {
      const req = createRequest('/blog/');
      const res = await middleware(req);

      expect(res.status).toBe(200);
    });

    it('should treat /pricing/ same as /pricing', async () => {
      const req = createRequest('/pricing/');
      const res = await middleware(req);

      expect(res.status).toBe(200);
    });
  });
});
